import { sqliteTable, text, integer } from "drizzle-orm/sqlite-core";
export const projects = sqliteTable("projects", {
    id: integer("id").primaryKey({ autoIncrement: true }),
    name: text("name").notNull(),
    createdAt: integer("created_at", { mode: "timestamp_ms" }).notNull(),
    updatedAt: integer("updated_at", { mode: "timestamp_ms" }).notNull(),
});
export const pages = sqliteTable("pages", {
    id: integer("id").primaryKey({ autoIncrement: true }),
    projectId: integer("project_id").notNull(),
    url: text("url").notNull(),
    title: text("title").notNull().default(""),
    screenshotPaths: text("screenshot_paths").notNull().default("[]"),
    interactiveElements: text("interactive_elements").notNull().default("[]"),
    globalStyles: text("global_styles"),
    annotatedScreenshotPath: text("annotated_screenshot_path"),
    lastCrawledAt: integer("last_crawled_at", { mode: "timestamp_ms" }),
    lastCrawlJobId: text("last_crawl_job_id"),
    lastCrawlRunId: integer("last_crawl_run_id"),
    createdAt: integer("created_at", { mode: "timestamp_ms" }).notNull(),
    updatedAt: integer("updated_at", { mode: "timestamp_ms" }).notNull(),
});
export const crawlRuns = sqliteTable("crawl_runs", {
    id: integer("id").primaryKey({ autoIncrement: true }),
    projectId: integer("project_id").notNull(),
    jobId: text("job_id"),
    startUrl: text("start_url").notNull(),
    settingsJson: text("settings_json").notNull().default("{}"),
    pageIdsJson: text("page_ids_json").notNull().default("[]"),
    pageCount: integer("page_count").notNull().default(0),
    elementCount: integer("element_count").notNull().default(0),
    status: text("status").notNull().default("completed"),
    startedAt: integer("started_at", { mode: "timestamp_ms" }).notNull(),
    completedAt: integer("completed_at", { mode: "timestamp_ms" }),
});
export const inventoryBuilds = sqliteTable("inventory_builds", {
    id: integer("id").primaryKey({ autoIncrement: true }),
    projectId: integer("project_id").notNull(),
    crawlRunId: integer("crawl_run_id"),
    workspacePath: text("workspace_path").notNull(),
    schemaVersion: integer("schema_version").notNull(),
    pageCount: integer("page_count").notNull().default(0),
    elementCount: integer("element_count").notNull().default(0),
    status: text("status").notNull().default("completed"),
    startedAt: integer("started_at", { mode: "timestamp_ms" }).notNull(),
    completedAt: integer("completed_at", { mode: "timestamp_ms" }),
});
export const elements = sqliteTable("elements", {
    id: integer("id").primaryKey({ autoIncrement: true }),
    pageId: integer("page_id").notNull(),
    projectId: integer("project_id").notNull(),
    type: text("type").notNull(),
    selector: text("selector"),
    tagName: text("tag_name"),
    elementId: text("element_id"),
    classes: text("classes").notNull().default("[]"),
    bbox: text("bbox"),
    href: text("href"),
    text: text("text"),
    styles: text("styles").notNull().default("{}"),
    styleTokens: text("style_tokens").notNull().default("[]"),
    ariaLabel: text("aria_label"),
    role: text("role"),
    parentTag: text("parent_tag"),
    parentSelector: text("parent_selector"),
    ancestryPath: text("ancestry_path"),
    nearestInteractiveSelector: text("nearest_interactive_selector"),
    isVisible: integer("is_visible", { mode: "boolean" }),
    regionLabel: text("region_label"),
    styleSignature: text("style_signature"),
    componentFingerprint: text("component_fingerprint"),
    parentFingerprint: text("parent_fingerprint"),
    childCount: integer("child_count").default(0),
    cropPath: text("crop_path"),
    cropContextPath: text("crop_context_path"),
    cropError: text("crop_error"),
    isGlobalChrome: integer("is_global_chrome", { mode: "boolean" }).default(false),
    value: text("value"),
    placeholder: text("placeholder"),
    checked: integer("checked", { mode: "boolean" }),
    src: text("src"),
    alt: text("alt"),
    createdAt: integer("created_at", { mode: "timestamp_ms" }).notNull(),
    updatedAt: integer("updated_at", { mode: "timestamp_ms" }).notNull(),
});
